import org.apache.spark.sql.{SparkSession, DataFrame}
import org.json4s._
import org.json4s.jackson.JsonMethods._
import spray.routing._
import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.stream.ActorMaterializer

object SparkSQLQueryService extends App with SimpleRoutingApp {
  implicit val system = ActorSystem("spark-sql-query-service")
  implicit val materializer = ActorMaterializer()
  implicit val executionContext = system.dispatcher
  implicit val formats: Formats.type = DefaultFormats

  // Initialize SparkSession
  val spark = SparkSession.builder()
    .appName("SparkSQLQueryService")
    .enableHiveSupport() // Enable Hive support if needed
    .getOrCreate()

  // Dummy data for demonstration purposes
  val df = Seq(
    (1, "Alice", 30),
    (2, "Bob", 25),
    (3, "Charlie", 35)
  ).toDF("id", "name", "age")

  df.createOrReplaceTempView("users") // Register DataFrame as a temporary view

  // Define the route
  val route =
    path("query") {
      post {
        entity(as[String]) { query =>
          try {
            val result: DataFrame = spark.sql(query)
            complete(result.toJSON.collect().mkString("[", ",", "]"))
          } catch {
            case e: Exception => complete(StatusCodes.BadRequest, s"Error executing query: ${e.getMessage}")
          }
        }
      }
    }

  // Start the HTTP server
  Http().newServerAt("localhost", 8080).bind(route)

  println("Spark SQL Query Service is running on http://localhost:8080/query")
